import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjIndexer } from "./OjIndexer";
export { OjIndexer };

/**
 * Create an instance of [[OjIndexer]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojIndexer(driver, By.id('my-oj-indexer'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojIndexer(driver: DriverLike, by: By): Promise<OjIndexer> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjIndexer
  if (!(webEl instanceof OjIndexer)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-indexer>`);
  }
  return webEl;
}

register("oj-indexer", OjIndexer);
